package com.auction.client.service;

import com.app.common.dto.AuctionListDTO;
import com.app.common.dto.PlaceBidRequestDTO;
import com.app.common.dto.PlaceBidResponseDTO;
import com.app.common.enums.Status;
import com.auction.client.session.SessionManager;

import java.util.ArrayList;
import java.util.List;

public class AuctionService {
    public List<AuctionListDTO> getActiveAuctions() {
        String response = sendCommand("LIST_AUCTIONS");
        return parseAuctionListResponse(response);
    }

    public AuctionListDTO getAuctionById(String auctionId) {
        if (isBlank(auctionId)) {
            return null;
        }

        String response = sendCommand("GET_AUCTION " + auctionId);
        return parseAuctionDetailResponse(response);
    }

    public PlaceBidResponseDTO placeBid(String auctionId, double bidAmount) {
        PlaceBidRequestDTO request = new PlaceBidRequestDTO();
        request.setAuctionId(auctionId);
        request.setBidderId(SessionManager.getCurrentUserId());
        request.setBidAmount(bidAmount);
        return placeBid(request);
    }

    public PlaceBidResponseDTO placeBid(PlaceBidRequestDTO request) {
        if (isInvalidBidRequest(request)) {
            return createPlaceBidResponse(false, "Thông tin đặt giá không hợp lệ.", null, null, 0);
        }

        if (!SessionManager.hasRole("Bidder")) {
            return createPlaceBidResponse(false, "Chỉ người đấu giá mới được đặt giá.", null, null, 0);
        }

        if (isBlank(request.getBidderId())) {
            request.setBidderId(SessionManager.getCurrentUserId());
        }

        try {
            String cmd = String.format(
                    "PLACE_BID %s %s %s",
                    request.getAuctionId(),
                    request.getBidderId(),
                    request.getBidAmount()
            );
            String resp = SocketClientService.sendSessionCommand(cmd);
            System.out.println("[AuctionService] PLACE_BID sent: " + cmd + " | resp=" + resp);
            return parsePlaceBidResponse(resp, request.getBidAmount());
        } catch (Exception e) {
            throw new IllegalStateException("Không thể gửi yêu cầu đấu giá tới server.", e);
        }
    }

    private boolean isInvalidBidRequest(PlaceBidRequestDTO request) {
        return request == null
                || isBlank(request.getAuctionId())
                || isBlank(request.getBidderId())
                || request.getBidAmount() <= 0;
    }

    private boolean isBlank(String value) {
        return value == null || value.isBlank();
    }

    private String sendCommand(String command) {
        try {
            return SocketClientService.sendText(command);
        } catch (Exception e) {
            throw new IllegalStateException("Không thể gửi yêu cầu đấu giá tới server.", e);
        }
    }

    private List<AuctionListDTO> parseAuctionListResponse(String response) {
        List<AuctionListDTO> auctions = new ArrayList<>();
        if (response == null || response.isBlank() || response.startsWith("ERR|") || "OK|AUCTIONS|EMPTY".equals(response)) {
            return auctions;
        }

        if (!response.startsWith("OK|AUCTIONS|")) {
            return auctions;
        }

        String[] parts = response.split("\\|");
        for (int i = 2; i < parts.length; i++) {
            AuctionListDTO auction = parseAuctionRecord(parts[i]);
            if (auction != null) {
                auctions.add(auction);
            }
        }
        return auctions;
    }

    private AuctionListDTO parseAuctionDetailResponse(String response) {
        if (response == null || response.isBlank() || response.startsWith("ERR|") || !response.startsWith("OK|AUCTION|")) {
            return null;
        }

        String[] parts = response.split("\\|", 3);
        if (parts.length < 3) {
            return null;
        }
        return parseAuctionRecord(parts[2]);
    }

    private AuctionListDTO parseAuctionRecord(String record) {
        if (record == null || record.isBlank()) {
            return null;
        }

        try {
            String[] fields = record.split(",", -1);
            if (fields.length < 5) {
                return null;
            }

            AuctionListDTO auction = new AuctionListDTO();
            auction.setAuctionId(fields[0]);
            auction.setItemId(fields[1]);
            auction.setName(fields[2]);
            auction.setCurrentPrice(Double.parseDouble(fields[3]));
            auction.setAuctionStatus(Status.valueOf(fields[4]));
            return auction;
        } catch (Exception e) {
            return null;
        }
    }

    private PlaceBidResponseDTO parsePlaceBidResponse(String response, double amount) {
        if (response == null || response.isBlank()) {
            return createPlaceBidResponse(false, "Server không phản hồi.", null, null, 0);
        }

        if (response.startsWith("OK|BID_PLACED|")) {
            String[] parts = response.split("\\|", 5);
            if (parts.length >= 5) {
                PlaceBidResponseDTO dto = new PlaceBidResponseDTO();
                dto.setSuccess(true);
                dto.setMessage("Đặt giá thành công.");
                dto.setBidId(parts[2]);
                dto.setAuctionId(parts[3]);
                dto.setBidAmount(parseAmount(parts[4], amount));
                return dto;
            }
            return createPlaceBidResponse(false, "Phản hồi đặt giá không hợp lệ.", null, null, 0);
        }

        if (response.startsWith("ERR|")) {
            String message = extractErrorMessage(response);
            return createPlaceBidResponse(false, message, null, null, 0);
        }

        return createPlaceBidResponse(false, "Phản hồi đặt giá không hợp lệ.", null, null, 0);
    }

    private double parseAmount(String value, double fallback) {
        try {
            return Double.parseDouble(value);
        } catch (Exception e) {
            return fallback;
        }
    }

    private PlaceBidResponseDTO createPlaceBidResponse(
            boolean success,
            String message,
            String bidId,
            String auctionId,
            double bidAmount
    ) {
        PlaceBidResponseDTO response = new PlaceBidResponseDTO();
        response.setSuccess(success);
        response.setMessage(message);
        response.setBidId(bidId);
        response.setAuctionId(auctionId);
        response.setBidAmount(bidAmount);
        return response;
    }

    private String extractErrorMessage(String response) {
        String[] parts = response.split("\\|", 3);
        if (parts.length >= 3) {
            return parts[2];
        }
        if (parts.length >= 2) {
            return parts[1];
        }
        return "Đặt giá thất bại.";
    }
}

package com.auction.client.service;

import com.app.common.dto.AuctionListDTO;
import com.app.common.dto.PlaceBidRequestDTO;
import com.app.common.dto.PlaceBidResponseDTO;
import com.app.common.enums.Status;
import com.auction.client.session.SessionManager;
import com.auction.client.service.SocketClientService;

import java.util.ArrayList;
import java.util.List;

public class AuctionService {
    public static class CreateAuctionResult {
        private final boolean success;
        private final String message;
        private final String auctionId;

        public CreateAuctionResult(boolean success, String message, String auctionId) {
            this.success = success;
            this.message = message;
            this.auctionId = auctionId;
        }

        public boolean isSuccess() {
            return success;
        }

        public String getMessage() {
            return message;
        }

        public String getAuctionId() {
            return auctionId;
        }
    }

    public CreateAuctionResult createArtAuction(
            String name,
            String description,
            String startDate,
            String endDate,
            double startPrice,
            String minIncrement,
            String author
    ) {
        if (!SessionManager.hasRole("Seller")) {
            return new CreateAuctionResult(false, "Chỉ Seller mới được tạo phiên.", null);
        }

        String payload = String.join(
                "|",
                name,
                description,
                startDate,
                endDate,
                String.valueOf(startPrice),
                minIncrement,
                author
        );
        String command = "CREATE_ART_AUCTION " + payload;
        String response;
        try {
            response = SocketClientService.sendSessionCommand(command);
        } catch (Exception e) {
            return new CreateAuctionResult(false, "Không thể gửi yêu cầu tới server.", null);
        }

        if (response == null || response.isBlank()) {
            return new CreateAuctionResult(false, "Server không phản hồi.", null);
        }

        if (response.startsWith("ERR|")) {
            return new CreateAuctionResult(false, response.substring(4), null);
        }

        if (response.startsWith("OK|CREATE_ART_AUCTION|")) {
            String[] parts = response.split("\\|", 4);
            String auctionId = parts.length >= 3 ? parts[2] : null;
            return new CreateAuctionResult(true, "Tạo phiên thành công.", auctionId);
        }

        return new CreateAuctionResult(false, "Phản hồi không hợp lệ: " + response, null);
    }

    public List<AuctionListDTO> getActiveAuctions() {
        String response = sendCommand("LIST_AUCTIONS");
        return parseAuctionListResponse(response);
    }

    public AuctionListDTO getAuctionById(String auctionId) {
        if (isBlank(auctionId)) {
            return null;
        }

        String response = sendCommand("GET_AUCTION " + auctionId);
        return parseAuctionDetailResponse(response);
    }

    public PlaceBidResponseDTO placeBid(String auctionId, double bidAmount) {
        PlaceBidRequestDTO request = new PlaceBidRequestDTO();
        request.setAuctionId(auctionId);
        request.setBidderId(SessionManager.getCurrentUserId());
        request.setBidAmount(bidAmount);
        return placeBid(request);
    }

    public PlaceBidResponseDTO placeBid(PlaceBidRequestDTO request) {
        if (isInvalidBidRequest(request)) {
            return createPlaceBidResponse(false, "Thông tin đặt giá không hợp lệ.", null, null, 0);
        }

        if (!SessionManager.hasRole("Bidder")) {
            return createPlaceBidResponse(false, "Chỉ người đấu giá mới được đặt giá.", null, null, 0);
        }

        if (isBlank(request.getBidderId())) {
            request.setBidderId(SessionManager.getCurrentUserId());
        }

        try {
            String cmd = String.format(
                    "PLACE_BID %s %s %s",
                    request.getAuctionId(),
                    request.getBidderId(),
                    request.getBidAmount()
            );
            String resp = SocketClientService.sendSessionCommand(cmd);
            System.out.println("[AuctionService] PLACE_BID sent: " + cmd + " | resp=" + resp);
            return parsePlaceBidResponse(resp, request.getBidAmount());
        } catch (Exception e) {
            throw new IllegalStateException("Không thể gửi yêu cầu đấu giá tới server.", e);
        }
    }

    private boolean isInvalidBidRequest(PlaceBidRequestDTO request) {
        return request == null
                || isBlank(request.getAuctionId())
                || isBlank(request.getBidderId())
                || request.getBidAmount() <= 0;
    }

    private boolean isBlank(String value) {
        return value == null || value.isBlank();
    }

    private String sendCommand(String command) {
        try {
            return SocketClientService.sendText(command);
        } catch (Exception e) {
            throw new IllegalStateException("Không thể gửi yêu cầu đấu giá tới server.", e);
        }
    }

    private List<AuctionListDTO> parseAuctionListResponse(String response) {
        List<AuctionListDTO> auctions = new ArrayList<>();
        if (response == null || response.isBlank() || response.startsWith("ERR|") || "OK|AUCTIONS|EMPTY".equals(response)) {
            return auctions;
        }

        if (!response.startsWith("OK|AUCTIONS|")) {
            return auctions;
        }

        String[] parts = response.split("\\|");
        for (int i = 2; i < parts.length; i++) {
            AuctionListDTO auction = parseAuctionRecord(parts[i]);
            if (auction != null) {
                auctions.add(auction);
            }
        }
        return auctions;
    }

    private AuctionListDTO parseAuctionDetailResponse(String response) {
        if (response == null || response.isBlank() || response.startsWith("ERR|") || !response.startsWith("OK|AUCTION|")) {
            return null;
        }

        String[] parts = response.split("\\|", 3);
        if (parts.length < 3) {
            return null;
        }
        return parseAuctionRecord(parts[2]);
    }

    private AuctionListDTO parseAuctionRecord(String record) {
        if (record == null || record.isBlank()) {
            return null;
        }

        try {
            String[] fields = record.split(",", -1);
            if (fields.length < 5) {
                return null;
            }

            AuctionListDTO auction = new AuctionListDTO();
            auction.setAuctionId(fields[0]);
            auction.setItemId(fields[1]);
            auction.setName(fields[2]);
            auction.setCurrentPrice(Double.parseDouble(fields[3]));
            auction.setAuctionStatus(Status.valueOf(fields[4]));
            return auction;
        } catch (Exception e) {
            return null;
        }
    }

    private PlaceBidResponseDTO parsePlaceBidResponse(String response, double amount) {
        if (response == null || response.isBlank()) {
            return createPlaceBidResponse(false, "Server không phản hồi.", null, null, 0);
        }

        if (response.startsWith("OK|BID_PLACED|")) {
            String[] parts = response.split("\\|", 5);
            if (parts.length >= 5) {
                PlaceBidResponseDTO dto = new PlaceBidResponseDTO();
                dto.setSuccess(true);
                dto.setMessage("Đặt giá thành công.");
                dto.setBidId(parts[2]);
                dto.setAuctionId(parts[3]);
                dto.setBidAmount(parseAmount(parts[4], amount));
                return dto;
            }
            return createPlaceBidResponse(false, "Phản hồi đặt giá không hợp lệ.", null, null, 0);
        }

        if (response.startsWith("ERR|")) {
            String message = extractErrorMessage(response);
            return createPlaceBidResponse(false, message, null, null, 0);
        }

        return createPlaceBidResponse(false, "Phản hồi đặt giá không hợp lệ.", null, null, 0);
    }

    private double parseAmount(String value, double fallback) {
        try {
            return Double.parseDouble(value);
        } catch (Exception e) {
            return fallback;
        }
    }

    private PlaceBidResponseDTO createPlaceBidResponse(
            boolean success,
            String message,
            String bidId,
            String auctionId,
            double bidAmount
    ) {
        PlaceBidResponseDTO response = new PlaceBidResponseDTO();
        response.setSuccess(success);
        response.setMessage(message);
        response.setBidId(bidId);
        response.setAuctionId(auctionId);
        response.setBidAmount(bidAmount);
        return response;
    }

    private String extractErrorMessage(String response) {
        String[] parts = response.split("\\|", 3);
        if (parts.length >= 3) {
            return parts[2];
        }
        if (parts.length >= 2) {
            return parts[1];
        }
        return "Đặt giá thất bại.";
    }
}

package com.auction.client.service;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.net.Socket;
import java.net.UnknownHostException;
import java.util.function.Consumer;

/**
 * AuctionSocketClient: Lớp tiện ích để kết nối tới AuctionSocketServer
 * - Kết nối TCP socket tới server
 * - Gửi lệnh dạng text (như trong protocol của server)
 * - Lắng nghe responses và sự kiện realtime (EVENT|...)
 *
 * Usage:
 *   AuctionSocketClient client = new AuctionSocketClient();
 *   client.connect("localhost", 5000, line -> System.out.println("EVENT: " + line));
 *   String resp = client.sendCommand("HELP");
 */
public class AuctionSocketClient {
    private Socket socket;
    private PrintWriter writer;
    private BufferedReader reader;
    private Thread listenerThread;
    private volatile boolean running;

    /**
     * Kết nối tới server và bắt đầu listener thread để nhận các dòng trả về
     * @param host địa chỉ server
     * @param port cổng
     * @param eventHandler callback nhận các dòng bắt đầu bằng "EVENT|" (realtime)
     * @throws IOException khi không kết nối được
     */
    public void connect(String host, int port, Consumer<String> eventHandler) throws IOException {
        try {
            socket = new Socket(host, port);
            writer = new PrintWriter(socket.getOutputStream(), true);
            reader = new BufferedReader(new InputStreamReader(socket.getInputStream()));

            // Đọc dòng chào mừng đầu tiên (server gửi khi kết nối)
            String welcome = reader.readLine();
            if (welcome != null) {
                // Có thể xử lý welcome nếu cần
                System.out.println("SERVER: " + welcome);
            }

            running = true;
            listenerThread = new Thread(() -> {
                try {
                    String line;
                    while (running && (line = reader.readLine()) != null) {
                        // Nếu là sự kiện realtime, chuyển cho handler
                        if (line.startsWith("EVENT|") && eventHandler != null) {
                            try {
                                eventHandler.accept(line);
                            } catch (Exception ignored) {
                            }
                        } else {
                            // Non-event dòng: in ra để debug
                            System.out.println("SERVER: " + line);
                        }
                    }
                } catch (IOException e) {
                    if (running) {
                        System.err.println("Listener error: " + e.getMessage());
                    }
                }
            }, "auction-client-listener");
            listenerThread.setDaemon(true);
            listenerThread.start();

        } catch (UnknownHostException e) {
            throw new IOException("Unknown host: " + host, e);
        }
    }

    /**
     * Gửi 1 command tới server và chờ 1 dòng phản hồi (blocking)
     * NOTE: Server có thể gửi thêm EVENTs bất kỳ lúc nào - listener sẽ in/forward chúng.
     * @param command ví dụ: "LOGIN alice pass" hoặc "PLACE_BID auctionId bidderId 100"
     * @return dòng phản hồi đầu tiên từ server (có thể là OK|... hoặc ERR|...)
     * @throws IOException khi đọc/ghi lỗi
     */
    public synchronized String sendCommand(String command) throws IOException {
        if (socket == null || socket.isClosed()) {
            throw new IOException("Not connected to server");
        }
        // Ghi lệnh xuống server
        writer.println(command);
        // Đọc trả lời ngay sau đó (blocking)
        String response = reader.readLine();
        return response;
    }

    /**
     * Ngắt kết nối và stop listener
     */
    public void disconnect() {
        running = false;
        try {
            if (socket != null && !socket.isClosed()) {
                try {
                    writer.println("QUIT");
                } catch (Exception ignored) {
                }
                socket.close();
            }
        } catch (IOException e) {
            System.err.println("Error while disconnecting: " + e.getMessage());
        }
    }

    // Convenience methods for common commands
    public String help() throws IOException { return sendCommand("HELP"); }
    public String login(String username, String password) throws IOException { return sendCommand("LOGIN " + username + " " + password); }
    public String registerBidder(String username, String password, String email) throws IOException { return sendCommand("REGISTER_BIDDER " + username + " " + password + " " + email); }
    public String deposit(String userId, double amount) throws IOException { return sendCommand("DEPOSIT " + userId + " " + amount); }
    public String listAuctions() throws IOException { return sendCommand("LIST_AUCTIONS"); }
    public String placeBid(String auctionId, String bidderId, double amount) throws IOException { return sendCommand("PLACE_BID " + auctionId + " " + bidderId + " " + amount); }
}
